+    if (raw != 0) {
+        const buf: wgpu.c.WGPUBuffer = @ptrFromInt(@as(usize, @intCast(raw)));
+        wgpu.releasePersistentBuffer(buf);
+    }
+    var undef: c.napi_value = undefined;
+    _ = c.napi_get_undefined(env, &undef);
+    return undef;
